use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum Phase {
    Solid,
    Liquid,
    Gas,
    Plasma,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum Group {
    AlkaliMetal,
    AlkalineEarthMetal,
    TransitionMetal,
    PostTransitionMetal,
    Metalloid,
    ReactiveNonmetal,
    NobleGas,
    Lanthanide,
    Actinide,
    Unknown,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Element {
    pub atomic_number: u8,
    pub symbol: &'static str,
    pub name: &'static str,
    pub atomic_mass: f64,       // unified atomic mass units
    pub group: Group,
    pub period: u8,
    pub melting_point_k: Option<f64>,
    pub boiling_point_k: Option<f64>,
    pub density_g_cm3: Option<f64>,
    pub electronegativity: Option<f64>, // Pauling scale
    pub abundance_crust_ppm: Option<f64>, // parts per million in Earth's crust
    pub abundance_universe_ppm: Option<f64>,
}

impl Element {
    pub fn phase_at(&self, temp_k: f64) -> Phase {
        match (self.melting_point_k, self.boiling_point_k) {
            (Some(mp), Some(bp)) => {
                if temp_k < mp { Phase::Solid }
                else if temp_k < bp { Phase::Liquid }
                else { Phase::Gas }
            }
            (Some(mp), None) => {
                if temp_k < mp { Phase::Solid } else { Phase::Gas }
            }
            _ => Phase::Gas,
        }
    }

    pub fn is_volatile(&self) -> bool {
        matches!(self.boiling_point_k, Some(bp) if bp < 400.0)
    }
}

