pub fn element_by_number(n: u8) -> Option<Element> {
    periodic_table().into_iter().find(|e| e.atomic_number == n)
}

pub fn element_by_symbol(sym: &str) -> Option<Element> {
    periodic_table().into_iter().find(|e| e.symbol == sym)
}
